import{_ as a,o as i,c as e,ag as o}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"理念与文化","description":"","frontmatter":{},"headers":[],"relativePath":"zh/philosophy.md","filePath":"zh/philosophy.md"}'),r={name:"zh/philosophy.md"};function t(s,l,n,h,p,d){return i(),e("div",null,[...l[0]||(l[0]=[o('<h1 id="理念与文化" tabindex="-1">理念与文化 <a class="header-anchor" href="#理念与文化" aria-label="Permalink to &quot;理念与文化&quot;">​</a></h1><h2 id="devops-思维方式" tabindex="-1">DevOps 思维方式 <a class="header-anchor" href="#devops-思维方式" aria-label="Permalink to &quot;DevOps 思维方式&quot;">​</a></h2><p>DevOps 不仅仅是一组工具——它是一种文化和组织方法，强调软件开发者和 IT 运维团队之间的协作、自动化和持续改进。</p><h3 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to &quot;核心原则&quot;">​</a></h3><p><strong>1. 协作优于孤立</strong></p><ul><li>打破开发和运维团队之间的壁垒</li><li>培养应用和基础设施的共同所有权</li><li>鼓励跨职能交流和透明度</li></ul><p><strong>2. 自动化</strong></p><ul><li>消除手动、容易出错的流程</li><li>自动化测试、部署和基础设施配置</li><li>使用基础设施即代码来版本控制整个堆栈</li></ul><p><strong>3. 持续改进</strong></p><ul><li>测量、监控和迭代</li><li>从失败中学习，而不是指责</li><li>拥抱实验和快速反馈循环</li></ul><p><strong>4. 开源和社区</strong></p><ul><li>利用社区驱动的解决方案和标准</li><li>为生态系统做出贡献</li><li>基于经过验证、久经考验的工具进行构建</li></ul><h2 id="从瀑布流到持续交付" tabindex="-1">从瀑布流到持续交付 <a class="header-anchor" href="#从瀑布流到持续交付" aria-label="Permalink to &quot;从瀑布流到持续交付&quot;">​</a></h2><h3 id="传统方法-瀑布流" tabindex="-1">传统方法（瀑布流） <a class="header-anchor" href="#传统方法-瀑布流" aria-label="Permalink to &quot;传统方法（瀑布流）&quot;">​</a></h3><ul><li>长发布周期（季度、年度）</li><li>团队之间的手动交接</li><li>高风险部署</li><li>晚期缺陷发现</li><li>孤立的职责</li></ul><h3 id="devops-方法" tabindex="-1">DevOps 方法 <a class="header-anchor" href="#devops-方法" aria-label="Permalink to &quot;DevOps 方法&quot;">​</a></h3><ul><li>持续集成和部署</li><li>自动化测试和基础设施</li><li>低风险、频繁的发布</li><li>早期缺陷检测</li><li>共享责任和所有权</li></ul><h2 id="linux-基金会和开源社区" tabindex="-1">Linux 基金会和开源社区 <a class="header-anchor" href="#linux-基金会和开源社区" aria-label="Permalink to &quot;Linux 基金会和开源社区&quot;">​</a></h2><p>Linux 基金会通过以下项目促进了 180 多家企业的协作：</p><ul><li><strong>Hyperledger</strong>：企业区块链解决方案</li><li><strong>CNCF</strong>：云原生计算标准</li><li><strong>OpenJS</strong>：JavaScript 生态系统治理</li></ul><p>这些社区展示了开放协作和共享标准在解决复杂技术挑战中的力量。</p><h2 id="关键-devops-指标-dora" tabindex="-1">关键 DevOps 指标 (DORA) <a class="header-anchor" href="#关键-devops-指标-dora" aria-label="Permalink to &quot;关键 DevOps 指标 (DORA)&quot;">​</a></h2><p>使用这些指标来衡量 DevOps 的有效性：</p><ul><li><strong>部署频率</strong>：代码到达生产的频率</li><li><strong>变更周期时间</strong>：从提交到生产的时间</li><li><strong>平均恢复时间 (MTTR)</strong>：事故恢复的速度</li><li><strong>变更失败率</strong>：导致事故的部署百分比</li></ul><h2 id="devops-生命周期" tabindex="-1">DevOps 生命周期 <a class="header-anchor" href="#devops-生命周期" aria-label="Permalink to &quot;DevOps 生命周期&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>规划 → 构建 → 测试 → 发布 → 部署 → 运维 → 监控 → 反馈循环</span></span></code></pre></div><p>每个阶段都应该被自动化，并根据指标和反馈进行持续优化。</p><h2 id="建立-devops-文化" tabindex="-1">建立 DevOps 文化 <a class="header-anchor" href="#建立-devops-文化" aria-label="Permalink to &quot;建立 DevOps 文化&quot;">​</a></h2><h3 id="_1-共同目标" tabindex="-1">1. 共同目标 <a class="header-anchor" href="#_1-共同目标" aria-label="Permalink to &quot;1. 共同目标&quot;">​</a></h3><ul><li>将开发和运维围绕业务成果保持一致</li><li>使用对两个团队都有益的指标</li><li>庆祝共同的成功</li></ul><h3 id="_2-心理安全" tabindex="-1">2. 心理安全 <a class="header-anchor" href="#_2-心理安全" aria-label="Permalink to &quot;2. 心理安全&quot;">​</a></h3><ul><li>鼓励实验，不怕失败</li><li>从失败中学习，而不是惩罚</li><li>支持团队成长和技能发展</li></ul><h3 id="_3-自动化优先" tabindex="-1">3. 自动化优先 <a class="header-anchor" href="#_3-自动化优先" aria-label="Permalink to &quot;3. 自动化优先&quot;">​</a></h3><ul><li>将基础设施视为代码</li><li>自动化重复任务</li><li>投资工具和流程改进</li></ul><h3 id="_4-持续学习" tabindex="-1">4. 持续学习 <a class="header-anchor" href="#_4-持续学习" aria-label="Permalink to &quot;4. 持续学习&quot;">​</a></h3><ul><li>定期知识分享会议</li><li>跨学科交叉培训</li><li>跟上新兴工具和实践</li></ul><h2 id="devops-组织中的角色" tabindex="-1">DevOps 组织中的角色 <a class="header-anchor" href="#devops-组织中的角色" aria-label="Permalink to &quot;DevOps 组织中的角色&quot;">​</a></h2><ul><li><strong>软件工程师</strong>：拥有代码质量、测试和运维特性</li><li><strong>运维工程师</strong>：管理基础设施、监控和可靠性</li><li><strong>DevOps 工程师</strong>：构建桥接这些角色的工具和流程</li><li><strong>网站可靠性工程师（SREs）</strong>：专注于系统可靠性、容量和性能</li></ul><p>所有角色都朝着稳定性、速度和客户满意度的共同目标协作。</p>',39)])])}const g=a(r,[["render",t]]);export{c as __pageData,g as default};
